#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X; scanf("%lld", &X);
        long long N = X + 4;
        bool ok = false;
        if(N >= 9){
            for(long long d = 3; d * d <= N; ++d){
                if(N % d == 0 && N / d >= 3){
                    ok = true; break;
                }
            }
        }
        printf(ok ? "YES\n" : "NO\n");
    }
    return 0;
}

