import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        X = int(next(it))
        N = X + 4
        ok = False
        if N >= 9:
            d = 3
            while d * d <= N:
                if N % d == 0 and N // d >= 3:
                    ok = True
                    break
                d += 1
        out.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

